class Solution {
    public boolean isPossible(int[] nums) {
        int count = 0;
        for (int i = 0; i < nums.length - 2; i++) {
            if (nums[i + 2] - nums[i] == 2) {
                count++;
            }
        }
        return count >= 1;
    }
}
